19→@OptIn(ExperimentalMaterial3Api::class)
20→@Composable
21→fun AssistantSheet(
22→    onDismiss: () -> Unit,
23→    viewModel: AssistantViewModel = hiltViewModel()
24→) {
25→    val uiState by viewModel.uiState.collectAsState()
26→    val context = LocalContext.current
27→    var tts by remember { mutableStateOf<TextToSpeech?>(null) }
28→
29→    LaunchedEffect(Unit) {
30→        tts = TextToSpeech(context) { status ->
31→            if (status == TextToSpeech.SUCCESS) {
32→                tts?.language = Locale.CHINA
33→                tts?.setSpeechRate(0.9f)
34→            }
35→        }
36→    }
37→
38→    DisposableEffect(Unit) { onDispose { tts?.shutdown() } }
39→
40→    ModalBottomSheet(onDismissRequest = onDismiss) {
41→        Column(modifier = Modifier.padding(16.dp).fillMaxWidth()) {
42→            Text("🎙 智能语音助手", style = MaterialTheme.typography.titleLarge)
43→            Spacer(Modifier.height(12.dp))
44→
45→            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
46→                OutlinedButton(onClick = { viewModel.uploadDocument() }) {
47→                    Icon(Icons.Default.Description, null, Modifier.size(16.dp))
48→                    Spacer(Modifier.width(4.dp))
49→                    Text("上传文档")
50→                }
51→                Button(
52→                    onClick = {
53→                        val text = uiState.lectureText
54→                        if (text.isNotBlank()) {
55→                            // Segment and speak - ported from renderer.js speakLecture()
56→                            val chunks = TextSegmenter.segment(text)
57→                            var idx = 0
58→                            fun speakNext() {
59→                                if (idx >= chunks.size) return
60→                                tts?.speak(chunks[idx], TextToSpeech.QUEUE_ADD, null, "lecture_$idx")
61→                                idx++
62→                            }
63→                            tts?.setOnUtteranceProgressListener(object : UtteranceProgressListener() {
64→                                override fun onStart(utteranceId: String?) {}
65→                                override fun onDone(utteranceId: String?) { speakNext() }
66→                                @Deprecated("Deprecated") override fun onError(utteranceId: String?) {}
67→                            })
68→                            speakNext()
69→                        }
70→                    },
71→                    enabled = uiState.lectureText.isNotBlank()
72→                ) {
73→                    Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
74→                    Spacer(Modifier.width(4.dp))
75→                    Text("朗读讲稿")
76→                }
77→                OutlinedButton(onClick = { tts?.stop() }) {
78→                    Icon(Icons.Default.Stop, null, Modifier.size(16.dp))
79→                    Spacer(Modifier.width(4.dp))
80→                    Text("停止")
81→                }
82→            }
83→
84→            if (uiState.lectureText.isNotBlank()) {
85→                Spacer(Modifier.height(12.dp))
86→                Card(modifier = Modifier.fillMaxWidth().heightIn(max = 300.dp)) {
87→                    Text(
88→                        uiState.lectureText,
89→                        modifier = Modifier.padding(12.dp).verticalScroll(rememberScrollState()),
90→                        style = MaterialTheme.typography.bodyMedium
91→                    )
92→                }
93→            }
94→
95→            Spacer(Modifier.height(32.dp))
96→        }
97→    }
98→}
