 37→@OptIn(ExperimentalMaterial3Api::class)
 38→@Composable
 39→fun PlayerScreen(
 40→    videoPath: String,
 41→    subtitlePath: String?,
 42→    onBack: () -> Unit,
 43→    viewModel: PlayerViewModel = hiltViewModel()
 44→) {
 45→    val uiState by viewModel.uiState.collectAsState()
 46→    val context = LocalContext.current
 47→    val listState = rememberLazyListState()
 48→
 49→    // ExoPlayer
 50→    val exoPlayer = remember {
 51→        ExoPlayer.Builder(context).build().apply {
 52→            setMediaItem(MediaItem.fromUri(videoPath))
 53→            prepare()
 54→        }
 55→    }
 56→
 57→    // Load subtitles
 58→    LaunchedEffect(videoPath) {
 59→        viewModel.loadSubtitles(videoPath, subtitlePath)
 60→    }
 61→
 62→    // 30ms position polling (ported from renderer.js syncTimer)
 63→    LaunchedEffect(exoPlayer) {
 64→        while (isActive) {
 65→            if (exoPlayer.isPlaying) {
 66→                viewModel.updatePosition(exoPlayer.currentPosition)
 67→            }
 68→            delay(30)
 69→        }
 70→    }
 71→
 72→    // Auto-scroll subtitle list
 73→    LaunchedEffect(uiState.currentCueIndex) {
 74→        if (uiState.currentCueIndex >= 0) {
 75→            listState.animateScrollToItem(uiState.currentCueIndex)
 76→        }
 77→    }
 78→
 79→    DisposableEffect(Unit) {
 80→        onDispose { exoPlayer.release() }
 81→    }
 82→
 83→    Scaffold(
 84→        topBar = {
 85→            TopAppBar(
 86→                title = { Text("视频学习") },
 87→                navigationIcon = {
 88→                    IconButton(onClick = { exoPlayer.release(); onBack() }) {
 89→                        Icon(Icons.Default.ArrowBack, "返回")
 90→                    }
 91→                }
 92→            )
 93→        }
 94→    ) { padding ->
 95→        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
 96→            // Video Player
 97→            AndroidView(
 98→                factory = {
 99→                    PlayerView(context).apply {
100→                        player = exoPlayer
101→                        layoutParams = FrameLayout.LayoutParams(
102→                            ViewGroup.LayoutParams.MATCH_PARENT,
103→                            ViewGroup.LayoutParams.WRAP_CONTENT
104→                        )
105→                    }
106→                },
107→                modifier = Modifier.fillMaxWidth().heightIn(max = 300.dp)
108→            )
109→
110→            // Mode bar (学习/听写/重新转录)
111→            Row(
112→                modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
113→                horizontalArrangement = Arrangement.spacedBy(8.dp)
114→            ) {
115→                FilterChip(
116→                    selected = uiState.mode == "learn",
117→                    onClick = { viewModel.setMode("learn") },
118→                    label = { Text("学习模式") }
119→                )
120→                FilterChip(
121→                    selected = uiState.mode == "dictation",
122→                    onClick = { viewModel.setMode("dictation") },
123→                    label = { Text("听写模式") }
124→                )
125→                Spacer(Modifier.weight(1f))
126→                AssistChip(
127→                    onClick = { exoPlayer.pause(); viewModel.retranscribe(videoPath) },
128→                    enabled = !uiState.isTranscribing,
129→                    label = { Text(if (uiState.isTranscribing) "转录中..." else "🔄 重新转录") }
130→                )
131→            }
132→
133→            if (uiState.mode == "learn") {
134→                // === Learning Mode ===
135→                // Current subtitle with karaoke highlighting
136→                Card(
137→                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
138→                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)
139→                ) {
140→                    Column(modifier = Modifier.padding(16.dp)) {
141→                        if (uiState.currentCueIndex >= 0 && uiState.currentCueIndex < uiState.subtitles.size) {
142→                            val cue = uiState.subtitles[uiState.currentCueIndex]
143→                            val words = cue.text.split(Regex("\\s+")).filter { it.isNotBlank() }
144→                            val timings = viewModel.getAlignedTimings(words)
145→                            val currentSec = uiState.currentPositionMs / 1000.0
146→
147→                            // Karaoke-style word-by-word display - clickable for instant lookup
148→                            val annotatedText = buildAnnotatedString {
149→                                words.forEachIndexed { i, word ->
150→                                    val wt = timings.getOrNull(i)
151→                                    val style = when {
152→                                        wt != null && currentSec >= wt.s && currentSec < wt.e ->
153→                                            SpanStyle(color = MaterialTheme.colorScheme.primary, fontWeight = FontWeight.Bold, fontSize = 24.sp)
154→                                        wt != null && currentSec >= wt.e ->
