314→    fun analyzeSentence() {
315→        val sentence = _uiState.value.currentSentence
316→        if (sentence.isBlank()) return
317→        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }
318→
319→        viewModelScope.launch(Dispatchers.IO) {
320→            val lang = _uiState.value.currentLang
321→            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
322→            val config = aiConfigStore.config.first()
323→            val prompt = """分析${langName}句子："$sentence"
324→【翻译】中文翻译
325→【语法】1-2个关键语法点
326→【重点词汇】2-3个重要词汇及释义"""
327→            val result = aiService.chat(config, prompt)
328→            _uiState.update { it.copy(
329→                isAnalyzing = false,
330→                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
331→            )}
332→        }
333→    }
334→
335→    /** Favorite operations */
336→    suspend fun isFavorite(word: String): Boolean {
337→        return favoriteRepository.isFavorite(word, _uiState.value.currentLang)
338→    }
339→
340→    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
341→        viewModelScope.launch {
342→            val lang = _uiState.value.currentLang
343→            if (favoriteRepository.isFavorite(word, lang)) {
344→                favoriteRepository.remove(word, lang)
345→            } else {
346→                favoriteRepository.add(word, lang, phonetic, translation, _uiState.value.currentSentence)
347→            }
348→        }
349→    }
350→
351→    /** TTS */
352→    fun speak(text: String) {
353→        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, "word_tts")
354→    }
355→
356→    /** Dictation */
357→    fun nextDictation() {
358→        val nextIdx = (_uiState.value.dictationIndex + 1).coerceAtMost(_uiState.value.subtitles.size - 1)
359→        _uiState.update { it.copy(dictationIndex = nextIdx) }
360→    }
361→
362→    /** Get aligned word timings for current cue */
363→    fun getAlignedTimings(words: List<String>): List<WordTimestamp?> {
364→        val state = _uiState.value
365→        val cueIdx = state.currentCueIndex
366→        if (cueIdx < 0 || cueIdx >= state.subtitles.size || state.wordTimings.isEmpty()) {
367→            return List(words.size) { null }
368→        }
369→        val cue = state.subtitles[cueIdx]
370→        return WordAligner.alignWords(words, state.wordTimings, cue.startMs / 1000.0, cue.endMs / 1000.0)
371→    }
372→
373→    override fun onCleared() {
374→        tts?.shutdown()
375→        super.onCleared()
376→    }
377→}
